import React, {useState,useEffect} from 'react';
import axios from 'axios';
import {MapContainer,TileLayer,Marker,Popup} from 'react-leaflet';
import 'leaflet/dist/leaflet.css';

function App(){
 const [reports,setReports]=useState([]);
 const [level,setLevel]=useState("Low");

 useEffect(()=>{load();},[]);

 const load=async()=>{
  const res=await axios.get("http://localhost:5000/api/reports");
  setReports(res.data);
 }

 const submit=async(e)=>{
  e.preventDefault();
  navigator.geolocation.getCurrentPosition(async(pos)=>{
   const form=new FormData();
   form.append("waterLevel",level);
   form.append("lat",pos.coords.latitude);
   form.append("lng",pos.coords.longitude);
   form.append("image",e.target.image.files[0]);

   await axios.post("http://localhost:5000/api/report",form);
   alert("Report submitted");
   load();
  });
 }

 return(
  <div style={{padding:20,fontFamily:"Arial"}}>
   <h2>Varadhi Flood Reporting</h2>

   <form onSubmit={submit}>
    <select value={level} onChange={e=>setLevel(e.target.value)}>
     <option>Low</option>
     <option>Medium</option>
     <option>High</option>
    </select>
    <input type="file" name="image" required/>
    <button>Submit Report</button>
   </form>

   <h3>Flood Map</h3>
   <MapContainer center={[17.385,78.4867]} zoom={12} style={{height:400}}>
    <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>
    {reports.map((r,i)=>(
     <Marker key={i} position={[r.lat,r.lng]}>
      <Popup>
       Level: {r.waterLevel}<br/>
       {r.image && <img src={"http://localhost:5000/uploads/"+r.image} width="100"/>}
      </Popup>
     </Marker>
    ))}
   </MapContainer>
  </div>
 )
}
export default App;
